import hashlib, json, os
from datetime import datetime, timezone, date, timedelta
from pathlib import Path

LOG_DIR = Path("evidence/api_logs")
DAILY_SUMMARY_DIR = Path("evidence/daily_summaries")
DAILY_SUMMARY_DIR.mkdir(parents=True, exist_ok=True)

def aggregate_daily_evidence(target_date: date) -> dict:
    """
    Read all API call logs for a given date, compute aggregate metrics
    for each control, and write a signed daily summary.
    """
    date_str = target_date.isoformat()
    logs = []
    for f in LOG_DIR.glob("*.json"):
        try:
            record = json.loads(f.read_text())
        except Exception:
            continue
        if record.get("ts_utc", "").startswith(date_str):
            logs.append(record)

    if not logs:
        return {"date": date_str, "total_calls": 0}

    summary = {
        "date": date_str,
        "total_calls": len(logs),
        "controls": {
            "CONS-001": {
                "consent_granted": sum(1 for l in logs if l.get("consent_check") == "granted"),
                "consent_denied": sum(1 for l in logs if l.get("consent_check") == "denied"),
            },
            "PII-001": {
                "pii_detected_calls": sum(1 for l in logs if l.get("pii_entities_detected")),
                "pii_redacted_calls": sum(1 for l in logs if l.get("pii_redacted")),
            },
            "OUT-001": {
                "output_redaction_applied": sum(1 for l in logs if l.get("output_redaction_applied")),
            },
            "TOK-001": {
                "t1_alerts": sum(1 for l in logs if l.get("alert_tier") == 1),
                "t2_alerts": sum(1 for l in logs if l.get("alert_tier") == 2),
                "t3_alerts": sum(1 for l in logs if l.get("alert_tier") == 3),
                "mean_anomaly_score": round(
                    sum(l.get("token_anomaly_score", 0) for l in logs) / len(logs), 3
                ),
            },
        },
    }

    payload = json.dumps(summary, sort_keys=True, ensure_ascii=False).encode()
    sha = hashlib.sha256(payload).hexdigest()
    summary["sha256"] = sha

    out_path = DAILY_SUMMARY_DIR / f"{date_str}.json"
    out_path.write_text(json.dumps(summary, indent=2))
    return summary

# Usage: run nightly for yesterday
yesterday = date.today() - timedelta(days=1)
summary = aggregate_daily_evidence(yesterday)
print(f"Daily summary for {yesterday}: {summary['total_calls']} calls")
